class Node:
    def __init__(self, char):
        self.char = char
        self.left = None
        self.right = None

class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, char):
        if self.root is None:
            self.root = Node(char)
        else:
            self._insert_recursive(self.root, char)

    def _insert_recursive(self, current_node, char):
        if char < current_node.char:
            if current_node.left is None:
                current_node.left = Node(char)
            else:
                self._insert_recursive(current_node.left, char)
        else:
            if current_node.right is None:
                current_node.right = Node(char)
            else:
                self._insert_recursive(current_node.right, char)

def process_sequence(sequence):
    bst = BinarySearchTree()
    for char in sequence:
        bst.insert(char.lower())
    return bst

